import json

def main(args):
    message = args['message']
    msg_type = message.get('msg_type')

    if msg_type == 'text':
        content = json.loads(message.get('content', '{}'))
        text = content.get('text', '')
        return {'text': text, 'type': 'text'}
    elif msg_type == 'image':
        return {'type': 'image', 'image_key': message.get('image_key')}
    else:
        return {'type': 'unknown'}
